#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Transition { pub timestamp: i64, pub offset: i32, pub is_dst: bool, pub abbrev_idx: u16 }

#[derive(Debug, Clone, Copy)]
pub struct OffsetInfo {
    pub offset: i32,
    pub is_dst: bool,
    pub abbrev: &'static str,
}

pub fn get_tz_data(name: &str) -> Option<(&str, &'static [Transition], Option<usize>)> {
    let idx = TZ_ENTRIES.partition_point(|(n, _, _)| *n < name);
    if idx < TZ_ENTRIES.len() && TZ_ENTRIES[idx].0 == name {
        Some(TZ_ENTRIES[idx])
    } else { None }
}

#[inline(always)]
pub fn abbrev(idx: u16) -> &'static str {
    ABBREVS[idx as usize]
}

#[inline]
fn resolve_far_future(
    transitions: &[Transition],
    repeating_tail_start: Option<usize>,
    unix_timestamp: i64,
) -> Option<OffsetInfo> {
    if let Some(start) = repeating_tail_start {
        let cycle = &transitions[start..];
        if cycle.len() < 2 {
            return last_transition(transitions);
        }
        let first = &cycle[0];
        let last = &cycle[cycle.len() - 1];
        let period = last.timestamp - first.timestamp;
        if period <= 0 {
            return last_transition(transitions);
        }
        let elapsed = unix_timestamp - first.timestamp;
        if elapsed < 0 {
            return last_transition(transitions);
        }
        let position_in_cycle = elapsed % period;
        let idx = cycle.partition_point(|t| {
            (t.timestamp - first.timestamp) <= position_in_cycle
        });
        let chosen = if idx == 0 {
            &cycle[0]
        } else {
            &cycle[idx - 1]
        };
        Some(OffsetInfo {
            offset: chosen.offset,
            is_dst: chosen.is_dst,
            abbrev: abbrev(chosen.abbrev_idx),
        })
    } else {
        last_transition(transitions)
    }
}

#[inline(always)]
fn last_transition(transitions: &[Transition]) -> Option<OffsetInfo> {
    transitions.last().map(|t| OffsetInfo {
        offset: t.offset,
        is_dst: t.is_dst,
        abbrev: abbrev(t.abbrev_idx),
    })
}

/// Returns the UTC offset (in seconds) for the given IANA timezone
/// at the specified Unix timestamp. Returns `None` if the zone is unknown.
pub fn offset_at(name: &str, unix_timestamp: i64) -> Option<i32> {
    let (_, transitions, repeating_tail_start) = get_tz_data(name)?;
    let idx = transitions.partition_point(|t| t.timestamp <= unix_timestamp);
    if idx < transitions.len() {
        if idx == 0 {
            Some(transitions[0].offset)
        } else {
            Some(transitions[idx - 1].offset)
        }
    } else {
        resolve_far_future(transitions, repeating_tail_start, unix_timestamp)
            .map(|info| info.offset)
    }
}

/// Returns detailed offset information for the given IANA timezone
/// at the specified Unix timestamp.
pub fn offset_info_at(name: &str, unix_timestamp: i64) -> Option<OffsetInfo> {
    let (_, transitions, repeating_tail_start) = get_tz_data(name)?;
    let idx = transitions.partition_point(|t| t.timestamp <= unix_timestamp);
    if idx < transitions.len() {
        let t = if idx == 0 {
            &transitions[0]
        } else {
            &transitions[idx - 1]
        };
        Some(OffsetInfo {
            offset: t.offset,
            is_dst: t.is_dst,
            abbrev: abbrev(t.abbrev_idx),
        })
    } else {
        resolve_far_future(transitions, repeating_tail_start, unix_timestamp)
    }
}

